      { key: 'delivery_status', label: 'Status', type: 'select', options: ['pending', 'picked_up', 'in_transit', 'delivered', 'failed'] },
      { key: 'delivery_date', label: 'Delivery Date', type: 'date' },
      { key: 'delivery_time', label: 'Delivery Time', type: 'time' },
    ],
  };
  return maps[tab] || [];
}
